def get_ls_result(dir_path: str) -> str:
    try:
        # Validate dir_path to prevent directory traversal and ensure it's a directory
        if not os.path.isdir(dir_path):
            return ""
        result = subprocess.run(['/bin/ls', '-l', dir_path], capture_output=True, text=True, check=True)
        return result.stdout
    except (subprocess.CalledProcessError, FileNotFoundError, OSError) as e:
        return ""

